(202, NULL, 'Fasting Blood Glucose', 'سكر صائم', 13, NULL, NULL, 1, NULL, '150', 'تحليل سكر صائم (FBG) يقيس مستوى الجلوكوز في الدم بعد صيام 8–12 ساعة. يساعد في تقييم حالة الجسم بالنسبة لمقاومة الإنسولين، مقدمات السكري، ومرض السكري.\r\n✔️ تعليمات قبل إجراء التحليل\r\nصيام تام من 8 إلى 12 ساعة (مسموح شرب ماء فقط).\r\nتجنب المجهود البدني الشديد قبل التحليل.\r\nتجنب التوتر لأنه قد يرفع مستوى الجلوكوز.\r\nعدم تناول الأدوية التي تؤثر على السكر بدون استشارة الطبيب.\r\nتحليل مناسب لجميع الأعمار.', 'FBG', NULL, NULL, 1, 1, '2025-11-26 12:11:57', '2025-11-26 12:16:55'),
(203, NULL, 'Postprandial Blood Glucose', 'سكر فاطر', 13, NULL, NULL, 1, NULL, '120', 'تحليل سكر فاطر (PPBS) يقيس مستوى الجلوكوز في الدم بعد تناول وجبة عادية أو بعد ساعتين من تناول 75 غرام جلوكوز.\r\nيُستخدم لتقييم استجابة الجسم للسكر وتشخيص مقدمات السكري والسكري.\r\n✔️ تعليمات قبل إجراء التحليل\r\nيتم قياس السكر بعد ساعتين من تناول وجبة عادية أو مشروب الجلوكوز.\r\nتجنب المجهود البدني الشديد خلال الساعتين.\r\nعدم تناول الأدوية التي تؤثر على السكر إلا باستشارة الطبيب.\r\nمناسب لجميع الأعمار.', 'PPBS', NULL, NULL, 1, 1, '2025-11-26 12:24:13', '2025-11-26 12:24:13'),
(204, NULL, 'Glycated Hemoglobin', 'سكر تراكمي', 13, NULL, NULL, 1, NULL, '170', 'تحليل HbA1c يقيس نسبة الهيموجلوبين المرتبط بالجلوكوز في الدم، ويُظهر متوسط مستوى السكر خلال آخر 2–3 أشهر.\r\nيُعتبر من أهم التحاليل لمتابعة وتشخيص مرض السكري.\r\n✔️ تعليمات قبل إجراء التحليل\r\nلا يحتاج إلى صيام.\r\nيمكن إجراؤه في أي وقت من اليوم.\r\nبعض الحالات قد تؤثر على النتيجة مثل (الأنيميا، أمراض الدم، النزيف، أمراض الكلى).', 'HbA1c', NULL, NULL, 1, 1, '2025-11-26 12:29:19', '2025-11-26 12:29:19'),
(205, NULL, 'Creatinine', 'كرياتينين', 13, NULL, NULL, 1, NULL, '120', 'تحليل الكرياتينين يقيس مستوى مادة الكرياتينين الناتجة من تكسير العضلات ويتم التخلص منها عبر الكُلى.\r\nيساعد في تقييم وظائف الكلى ومعرفة قدرة الجسم على التخلص من السموم.\r\n✔️ تعليمات قبل إجراء التحليل\r\nلا يحتاج لصيام.\r\nيجب تجنب المجهود العضلي الشديد قبل التحليل.\r\nيفضل إبلاغ المعمل بالأدوية المتناولة خصوصًا:\r\nCimetidine – Trimethoprim – Creatine supplements – بعض المضادات الحيوية\r\nشرب الماء بشكل طبيعي قبل التحليل.', 'Cr', NULL, NULL, 1, 1, '2025-11-26 12:34:41', '2025-11-26 12:34:41'),
(206, NULL, 'Urea', 'يوريا', 13, NULL, NULL, 1, NULL, '200', 'تحليل اليوريا يقيس مستوى مادة urea في الدم، وهي ناتج نهائي لعملية تكسير البروتين، ويتم التخلص منها عبر الكُلى.\r\nيساعد في تقييم وظائف الكلى و مدى توازن البروتين والماء في الجسم.\r\n✔️ تعليمات قبل إجراء التحليل\r\n\r\nلا يحتاج لصيام (إلا إذا طلب الطبيب).\r\nتجنب تناول كمية كبيرة من البروتين قبل التحليل.\r\nشرب ماء بكمية طبيعية.\r\nبعض الأدوية قد تؤثر على النتيجة مثل:\r\nCorticosteroids – Tetracycline – Diuretics (مدرات البول)', 'Urea', NULL, NULL, 1, 1, '2025-11-26 12:41:31', '2025-11-26 12:41:31'),
(207, NULL, 'Uric Acid', 'حمض البوليك', 13, NULL, NULL, 1, NULL, '200', 'تحليل حمض البوليك يقيس مستوى حمض اليوريك في الدم، وهو ناتج تكسير البيورينات الموجودة في الطعام والخلايا.\r\nارتفاعه قد يسبب النقرس وقد يرتبط بمشاكل الكلى أو زيادة إنتاج الحمض.\r\n✔️ تعليمات قبل إجراء التحليل\r\nلا يشترط الصيام (قد يفضله بعض الأطباء للحصول على دقة أعلى).\r\nيفضل تجنب الطعام الغني بالبيورين لمدة 24 ساعة قبل التحليل:\r\n(الكبد والكلاوي – السردين – اللحوم الحمراء – البقوليات بكثرة)\r\nشرب ماء كافٍ قبل التحليل.\r\nبعض الأدوية تؤثر على النتيجة:\r\nAspirin – Diuretics مدرات البول – Allopurinol – Vitamin C – Steroids', 'UA', NULL, NULL, 1, 1, '2025-11-26 12:52:51', '2025-11-26 12:52:51'),
(208, NULL, 'Albumin', 'ألبيومين', 13, NULL, NULL, 1, NULL, '150', 'تحليل الألبومين يقيس مستوى بروتين الألبومين في الدم، وهو البروتين الرئيسي الذي يصنعه الكبد.\r\nيساعد في تقييم:\r\nوظائف الكبد\r\n\r\nالحالة الغذائية\r\nوظائف الكلى (خصوصًا عند وجود بروتين في البول)\r\nتوازن السوائل في الجسم\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام غير ضروري عادةً، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب التمارين العنيفة قبل التحليل.\r\nبعض الأدوية قد تؤثر على النتيجة: الكورتيزون – مضادات الالتهاب – أدوية القلب وبعض المضادات الحيوية', 'Alb', NULL, NULL, 1, 1, '2025-11-26 12:58:20', '2025-11-26 12:58:20'),
(209, NULL, 'Total Protein', 'البروتين الكلي', 13, NULL, NULL, 1, NULL, '110', 'تحليل البروتين الكلي يقيس مجموع البروتينات في الدم، بما في ذلك الألبومين والجلوبولين.\r\nيساعد في تقييم:\r\nوظائف الكبد\r\nوظائف الكلى\r\nالحالة الغذائية\r\nالكشف عن بعض أمراض الدم والمناعة\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب التمارين العنيفة قبل التحليل.\r\nبعض الأدوية قد تؤثر على النتائج: الكورتيزون، مضادات الالتهاب، أدوية القلب، وبعض المضادات الحيوية.', 'TP', NULL, NULL, 1, 1, '2025-11-26 13:04:28', '2025-11-26 13:04:28'),
(210, NULL, 'Calcium', 'كالسيوم', 13, NULL, NULL, 1, NULL, '190', 'يقيس مستوى الكالسيوم في الدم. الكالسيوم هو أحد أهم المعادن في الجسم، حيث يلعب دورًا حيويًا في:\r\nصحة العظام والأسنان.\r\nتقلص العضلات.\r\nوظيفة الأعصاب.\r\nتخثر الدم.\r\nتنظيم نبضات القلب.\r\nأنواع الكالسيوم في الدم:\r\nالكالسيوم المتأين (Ionized Calcium): الشكل الحر والنشط من الكالسيوم وهو الأكثر أهمية.\r\nالكالسيوم المرتبط بالبروتين (مثل الألبيومين): غير نشط.\r\nتحليل \"الكالسيوم الكلي\" يقيس كلا النوعين معًا.\r\nالغرض منه:\r\nتقييم وظيفة الغدة الجار درقية (التي تنظم مستوى الكالسيوم).\r\nتشخيص ومتابعة أمراض العظام والكلى.\r\nتقييم الحالات المرتبطة بالأعصاب والعضلات.\r\nمراقبة المرضى الذين يتلقون علاجات تؤثر على مستوى الكالسيوم.', 'Ca', NULL, NULL, 1, 1, '2025-11-26 13:14:18', '2025-11-26 13:14:18'),
(211, NULL, 'Sodium', 'صوديوم', 13, NULL, NULL, 1, NULL, '160', 'تحليل الصوديوم يقيس مستوى الصوديوم في الدم، وهو أهم الأيونات الكهربائية في الجسم، ويلعب دورًا رئيسيًا في:\r\nتوازن السوائل في الجسم\r\nتنظيم ضغط الدم\r\nوظيفة الأعصاب والعضلات\r\nنقل الإشارات الكهربائية في الجسم\r\n✔️ تعليمات قبل إجراء التحليل\r\nعادة لا يحتاج الصيام.\r\nشرب الماء طبيعي.\r\nتجنب تناول أدوية مدرات البول أو ملح الصوديوم بكميات كبيرة قبل التحليل إلا باستشارة الطبيب.\r\nبعض الأدوية قد تؤثر على النتيجة: مدرات البول، أدوية ضغط الدم، الكورتيزون.', 'Na', NULL, NULL, 1, 1, '2025-11-26 13:26:29', '2025-11-26 13:26:29'),
(212, NULL, 'Potassium', 'بوتاسيوم', 13, NULL, NULL, 1, NULL, '70', 'تحليل البوتاسيوم يقيس مستوى البوتاسيوم في الدم، وهو من أهم الأيونات الكهربائية الضرورية للجسم، ويلعب دورًا رئيسيًا في:\r\nوظيفة العضلات والأعصاب\r\nتنظيم ضربات القلب\r\nتوازن السوائل في الجسم\r\nضغط الدم\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري.\r\nشرب الماء طبيعي.\r\nتجنب تمارين مكثفة قبل التحليل لأنها قد ترفع مستوى البوتاسيوم مؤقتًا.\r\nبعض الأدوية تؤثر على النتيجة: مدرات البول، مثبطات ACE، أدوية القلب، الستيرويدات.', 'K', NULL, NULL, 1, 1, '2025-11-26 14:14:17', '2025-11-26 14:14:17'),
(213, NULL, 'Chloride', 'كلوريد', 13, NULL, NULL, 1, NULL, '130', 'تحليل الكلوريد يقيس مستوى أيون الكلوريد في الدم، وهو من أهم الشوارد التي تساعد على:\r\nالحفاظ على توازن السوائل والأحماض في الجسم\r\nالحفاظ على توازن الإلكتروليتات مع الصوديوم والبوتاسيوم\r\nدعم وظائف الأعصاب والعضلات\r\n✔️ تعليمات قبل إجراء التحليل\r\nعادة لا يحتاج الصيام.\r\nشرب الماء طبيعي.\r\nتجنب تناول أدوية مدرات البول أو ملح الصوديوم بكميات كبيرة قبل التحليل إلا باستشارة الطبيب.\r\nبعض الأدوية قد تؤثر على النتيجة: مدرات البول، أدوية ضغط الدم، الكورتيزون.', 'Cl', NULL, NULL, 1, 1, '2025-11-26 14:21:43', '2025-11-26 14:21:43'),
(214, NULL, 'Magnesium', 'مغنيسيوم', 13, NULL, NULL, 1, NULL, '110', 'تحليل المغنيسيوم يقيس مستوى المغنيسيوم في الدم، وهو معدن أساسي يقوم بالوظائف التالية:\r\nدعم وظيفة العضلات والأعصاب\r\nتنظيم ضربات القلب\r\nدعم قوة العظام\r\nالمشاركة في عمليات الأيض المختلفة وإنتاج الطاقة\r\n✔️ تعليمات قبل إجراء التحليل\r\nعادة لا يحتاج الصيام، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب المكملات الغذائية المحتوية على المغنيسيوم قبل التحليل مباشرة.\r\nبعض الأدوية تؤثر على النتيجة: مدرات البول، المضادات الحيوية، أدوية القلب، الستيرويدات.', 'Mg', NULL, NULL, 1, 1, '2025-11-26 14:32:03', '2025-11-26 14:32:03'),
(215, NULL, 'Phosphorus', 'فوسفور', 13, NULL, NULL, 1, NULL, '110', 'تحليل الفوسفور يقيس مستوى الفوسفور في الدم، وهو معدن أساسي يعمل على:\r\nبناء العظام والأسنان\r\nتنظيم الطاقة والتمثيل الغذائي (ATP)\r\nتوازن المعادن مع الكالسيوم والمغنيسيوم\r\nدعم وظيفة العضلات والأعصاب\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام غير ضروري عادةً، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب المكملات الغذائية المحتوية على الفوسفور قبل التحليل مباشرة.\r\nبعض الأدوية قد تؤثر على النتيجة: مدرات البول، أدوية القلب، الستيرويدات، مكملات الفوسفور.', 'Phos', NULL, NULL, 1, 1, '2025-11-26 14:38:11', '2025-11-26 14:38:11'),
(216, NULL, 'Total Bilirubin', 'بيليروبين كلي', 13, NULL, NULL, 1, NULL, '70', 'تحليل البيليروبين الكلي يقيس مستوى البيليروبين في الدم، وهو صبغة تنتج عن تحلل الهيموجلوبين من خلايا الدم الحمراء القديمة.\r\nيساعد في تقييم:\r\nوظائف الكبد\r\nمسار إخراج الصفراء\r\nالكشف عن اليرقان أو مشاكل الكبد أو القنوات الصفراوية\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام غير ضروري عادةً، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب المكملات الغذائية أو الأدوية التي تؤثر على الكبد قبل التحليل إلا باستشارة الطبيب.\r\nبعض الأدوية قد تؤثر على النتيجة: أسبرين، أدوية مضادة للصرع، بعض المضادات الحيوية، أدوية القلب.', 'TBIL', NULL, NULL, 1, 1, '2025-11-26 14:45:09', '2025-11-26 14:45:09'),
(217, NULL, 'Direct Bilirubin', 'بيليروبين مباشر', 13, NULL, NULL, 1, NULL, '90', 'تحليل البيليروبين المباشر يقيس مستوى البيليروبين المرتبط بالكبد والمذاب في الصفراء.\r\nيساعد في تقييم:\r\nوظائف الكبد وإنتاج الصفراء\r\nانسداد القنوات الصفراوية\r\nتمييز سبب ارتفاع البيليروبين الكلي (هل سببه الكبد أم تحلل الدم)\r\n✔️ تعليمات قبل إجراء التحليل\r\n\r\nالصيام عادة غير ضروري، لكن بعض الأطباء يفضلون صيام 8 ساعات.\r\nشرب الماء طبيعي.\r\nتجنب المكملات الغذائية أو الأدوية المؤثرة على الكبد قبل التحليل إلا باستشارة الطبيب.\r\nبعض الأدوية قد تؤثر على النتيجة: أسبرين، أدوية مضادة للصرع، بعض المضادات الحيوية، أدوية القلب.', 'DBIL', NULL, NULL, 1, 1, '2025-11-26 14:51:00', '2025-11-26 14:51:00'),
(218, NULL, 'Aspartate Aminotransferase', 'AST', 13, NULL, NULL, 1, NULL, '60', 'تحليل AST يقيس مستوى إنزيم Aspartate Aminotransferase في الدم، وهو إنزيم موجود في:\r\nالكبد\r\nالقلب\r\nالعضلات\r\nالكلى\r\nارتفاعه يشير غالبًا إلى ضرر في الكبد أو العضلات، ويستخدم مع ALT لتقييم وظائف الكبد.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري، لكن يفضل صيام 8 ساعات لبعض الحالات.\r\nتجنب التمارين العنيفة قبل التحليل لأنها قد ترفع AST مؤقتًا.\r\nبعض الأدوية قد تؤثر على النتيجة: أدوية الكبد، أدوية القلب، الأسبرين، الستيرويدات.', 'AST', NULL, NULL, 1, 1, '2025-11-26 14:56:39', '2025-11-26 14:56:39'),
(219, NULL, 'Alanine Aminotransferase', 'ALT', 13, NULL, NULL, 1, NULL, '90', 'تحليل ALT يقيس مستوى إنزيم Alanine Aminotransferase في الدم، وهو إنزيم يوجد بشكل رئيسي في الكبد.\r\nيُعد مؤشرًا حساسًا لضرر الكبد، ويستخدم مع AST لتقييم وظائف الكبد.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادةً غير ضروري، لكن يفضل صيام 8 ساعات لبعض الحالات.\r\nتجنب التمارين العنيفة قبل التحليل لأنها قد ترفع ALT مؤقتًا.\r\nبعض الأدوية قد تؤثر على النتيجة: أدوية الكبد، الأسبرين، الستيرويدات، أدوية القلب، مضادات الالتهاب.', 'ALT', NULL, NULL, 1, 1, '2025-11-26 15:04:25', '2025-11-26 15:04:25'),
(220, NULL, 'Alkaline Phosphatase', 'ALP', 13, NULL, NULL, 1, NULL, '90', 'تحليل ALP يقيس مستوى إنزيم الفوسفاتاز القلوي في الدم، وهو موجود في:\r\nالكبد\r\nالعظام\r\nالكلى\r\nالقنوات الصفراوية\r\nارتفاعه يشير غالبًا إلى مشاكل في الكبد أو العظام أو القنوات الصفراوية، ويستخدم لتقييم صحة الكبد والعظام.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري.\r\nتجنب المكملات الغذائية المحتوية على الكالسيوم أو الفيتامينات قبل التحليل.\r\nبعض الأدوية قد تؤثر على النتيجة: ستيرويدات، أدوية القلب، أدوية العظام، أدوية الكبد.\r\nالتمارين العنيفة قبل التحليل قد ترفع ALP مؤقتًا.', 'ALP', NULL, NULL, 1, 1, '2025-11-26 15:09:20', '2025-11-26 15:09:20'),
(221, NULL, 'Gamma Glutamyl Transferase', 'GGT', 13, NULL, NULL, 1, NULL, '80', 'تحليل GGT يقيس مستوى إنزيم Gamma Glutamyl Transferase في الدم، وهو إنزيم موجود في:\r\nالكبد (القنوات الصفراوية)\r\nالبنكرياس\r\nالكلى\r\nالقلب\r\nيُستخدم هذا التحليل لتقييم وظائف الكبد والقنوات الصفراوية وكمؤشر على تعاطي الكحول المزمن وبعض الأدوية.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري.\r\nتجنب الكحول قبل التحليل على الأقل 24 ساعة.\r\nبعض الأدوية تؤثر على GGT: أدوية الكبد، الأدوية المضادة للصرع، الأدوية المدرة للبول، أدوية القلب، الستيرويدات.\r\nالتمارين العنيفة قد ترفع GGT مؤقتًا.', 'GGT', NULL, NULL, 1, 1, '2025-11-26 15:15:27', '2025-11-26 15:15:27'),
(222, NULL, 'Lactate Dehydrogenase', 'LDH', 13, NULL, NULL, 1, NULL, '80', 'تحليل LDH يقيس مستوى إنزيم Lactate Dehydrogenase في الدم، وهو إنزيم موجود في:\r\nالقلب\r\nالكبد\r\nالعضلات\r\nالكلى\r\nالرئتين\r\nخلايا الدم الحمراء\r\nارتفاعه يشير إلى ضرر أو تحلل في أحد هذه الأنسجة.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام عادة غير ضروري.\r\nتجنب التمارين العنيفة قبل التحليل لأنها قد ترفع LDH مؤقتًا.\r\nبعض الأدوية قد تؤثر على النتيجة: ستيرويدات، أدوية القلب، أدوية الكبد، بعض المضادات الحيوية.', 'LDH', NULL, NULL, 1, 1, '2025-11-26 15:29:53', '2025-11-26 15:29:53'),
(223, NULL, 'Total Cholesterol', 'كوليستيرول كلي', 13, NULL, NULL, 1, NULL, '100', 'تحليل الكوليسترول الكلي يقيس مستوى جميع أنواع الكوليسترول في الدم، ويعتبر مؤشراً مهماً لتقييم:\r\nصحة القلب والأوعية الدموية\r\nخطر الإصابة بتصلب الشرايين وأمراض القلب\r\nالتوازن الغذائي والدهون في الجسم\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام 9-12 ساعة قبل التحليل للحصول على نتائج دقيقة.\r\nشرب الماء مسموح.\r\nتجنب تناول أطعمة غنية بالدهون قبل التحليل.\r\nبعض الأدوية قد تؤثر على النتائج: أدوية خفض الكوليسترول، الستيرويدات، مدرات البول، حبوب منع الحمل.', 'TC', NULL, NULL, 1, 1, '2025-11-26 15:34:44', '2025-11-26 15:34:44'),
(224, NULL, 'Triglycerides', 'تحليل الدهون الثلاثية الجليسريد', 13, NULL, NULL, 1, NULL, '110', 'تحليل الدهون الثلاثية يقيس مستوى الدهون الثلاثية في الدم، وهي نوع من الدهون يتم تخزينها في الجسم واستخدامها كمصدر للطاقة.\r\nيُستخدم لتقييم:\r\nخطر الإصابة بأمراض القلب والشرايين\r\nتوازن الدهون في الدم\r\nصحة الكبد والبنكرياس\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام 9-12 ساعة قبل التحليل للحصول على نتائج دقيقة.\r\nشرب الماء مسموح.\r\nتجنب الأطعمة الدهنية أو السكرية قبل التحليل.\r\nبعض الأدوية قد تؤثر على النتائج: أدوية خفض الدهون، الستيرويدات، أدوية السكري، حبوب منع الحمل.', 'TG', NULL, NULL, 1, 1, '2025-11-26 15:38:23', '2025-11-26 15:39:19'),
(225, NULL, 'HDL Cholesterol', 'HDL كوليستيرول', 13, NULL, NULL, 1, NULL, '170', 'تحليل HDL يقيس مستوى الكوليسترول الجيد في الدم.\r\nيعمل على نقل الكوليسترول من الشرايين إلى الكبد لإزالته من الجسم.\r\nارتفاعه يحمي من أمراض القلب والشرايين.\r\nانخفاضه يزيد خطر تصلب الشرايين والنوبات القلبية.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام 9-12 ساعة قبل التحليل للحصول على نتائج دقيقة.\r\nشرب الماء مسموح.\r\nتجنب الأطعمة الدهنية أو الكحول قبل التحليل.\r\nبعض الأدوية قد تؤثر على HDL: ستاتينات، حبوب منع الحمل، الستيرويدات، أدوية السكري.', 'HDL', NULL, NULL, 1, 1, '2025-11-26 15:44:09', '2025-11-26 15:44:09'),
(226, NULL, 'LDL Cholesterol', 'LDL كوليستيرول', 13, NULL, NULL, 1, NULL, '170', 'تحليل LDL يقيس مستوى الكوليسترول الضار في الدم.\r\nارتفاعه يزيد خطر تراكم الدهون على جدران الشرايين (تصلب الشرايين) ويزيد خطر النوبات القلبية والسكتات الدماغية.\r\nيفضل الحفاظ على مستويات LDL منخفضة للحماية من أمراض القلب.\r\n✔️ تعليمات قبل إجراء التحليل\r\nالصيام 9-12 ساعة قبل التحليل للحصول على نتائج دقيقة.\r\nشرب الماء مسموح.\r\nتجنب الأطعمة الدهنية والكحول قبل التحليل.\r\nبعض الأدوية قد تؤثر على LDL: ستاتينات، أدوية خفض الدهون، الستيرويدات، حبوب منع الحمل.', 'LDL', NULL, NULL, 1, 1, '2025-11-26 15:49:43', '2025-11-26 15:49:43'),
