INSERT INTO `settings` (`id`, `title_en`, `title_ar`, `content_en`, `content_ar`, `image`, `settings_type`, `app_type`, `status`, `created_at`, `updated_at`) VALUES
(1, 'terms clinic', 'شروط واحكام تطبيق العيادة', 'Providing accurate information\r\n\r\nThe user must enter accurate and correct details about his health condition and the purpose of the visit.\r\n\r\nThe user is responsible for any incorrect information that may affect the medical service provided.\r\n\r\nAdherence to appointments\r\n\r\nThe user is required to respect the booked appointments or cancel them in sufficient time if circumstances prevent him from attending.\r\n\r\nPaying fees\r\n\r\nThe user must pay any fees associated with the service, whether booking fees or medical consultation fees, through the payment methods available in the application.\r\n\r\nThe application is committed to clarifying the payment and refund policy in a transparent manner.\r\n\r\nPrivacy and data protection\r\n\r\nThe user must agree to the privacy policy that specifies how personal data is collected and used.\r\nThe applications are committed to protecting user data in accordance with the data protection systems and regulations in the Kingdom.', 'توفير معلومات دقيقة\r\n\r\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\r\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\r\n\r\n الالتزام بالمواعيد\r\n\r\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\r\n\r\nدفع الرسوم\r\n\r\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\r\n\r\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\r\n\r\n الخصوصية وحماية البيانات\r\n\r\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\r\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'terms', 1, 1, '2022-07-14 15:41:15', '2025-02-28 15:47:14'),
(2, 'About clinic ', 'عن تكافل ', 'An application that makes it easy for users to book medical appointments easily and quickly. The application allows you to browse doctors by specialties, book appointments by date and time, and view exclusive offers and available services. The application is compatible with insurance companies, allowing you to easily choose the clinics and covered services.\n\nBook appointments easily: Choose the date and time that suits you with immediate confirmation.\n\nSpecial offers: Discover the latest offers and discounts in clinic complexes.\n\nSecure electronic payment: Various payment options to facilitate the experience.\n\nThe goal of the application: Provide a comfortable and smooth experience for users to access the best', 'تطبيق يسهّل على المستخدمين حجز المواعيد الطبية بكل سهولة وسرعة. يتيح لك التطبيق استعراض الأطباء حسب التخصصات، حجز المواعيد بالتاريخ والساعة، والاطلاع على العروض الحصرية والخدمات المتوفرة. يتميز التطبيق بتوافقه مع شركات التأمين، مما يتيح لك اختيار العيادات والخدمات المغطاة بسهولة.\n\n    حجز المواعيد بسهولة: اختر التاريخ والساعة المناسبة لك مع تأكيد فوري.\n    عروض خاصة: اكتشف أحدث العروض والتخفيضات في مجمعات العيادات.\n    دفع إلكتروني آمن: خيارات دفع متنوعة لتسهيل التجربة.\n\nهدف التطبيق: تقديم تجربة مريحة وسلسة للمستخدمين للوصول إلى أفضل', NULL, 'about', 1, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(3, 'Privacy clinic ', 'شروط واحكام تطبيق العيادة', 'We are committed to protecting your privacy and ensuring the security of your personal data. Our Privacy Policy is designed to explain how we collect, use, and protect information to the highest standards of security.\n\nWhat do we do with your data?\n\nData Collection: We collect only basic information, such as name, contact information, and booking details, in order to provide the service efficiently.\n\nUse: Your data is used to organize appointments, provide appropriate offers, and ensure that services are compatible with your insurance coverage.\n\nData Protection: We apply modern technologies to protect your data from unauthorized access or illegal use.\n\nComplete Transparency\n\nWe will not share your personal data with any third party without your prior consent.\n\nYou can manage, update, or request deletion of your data at any time through your account settings or by contacting us.\n\nOur Goal\nTo ensure a safe and reliable experience that meets your medical needs while respecting your privacy at every step.\n\nFor more details, you can view the full text of the Privacy Policy via the application.', 'نحن  ملتزمون بحماية خصوصيتك وضمان أمان بياناتك الشخصية. تم تصميم سياسة الخصوصية لدينا لتوضيح كيفية جمع المعلومات، استخدامها، وحمايتها ضمن أعلى معايير الأمان.\n\nما الذي نفعله ببياناتك؟\n\n    جمع البيانات: نقوم بجمع المعلومات الأساسية فقط، مثل الاسم، بيانات التواصل، وتفاصيل الحجز، بهدف تقديم الخدمة بكفاءة.\n    الاستخدام: تُستخدم بياناتك لتنظيم المواعيد، توفير العروض المناسبة، والتأكد من توافق الخدمات مع تغطية التأمين الخاصة بك.\n    حماية البيانات: نطبق تقنيات حديثة لحماية بياناتك من الوصول غير المصرح به أو الاستخدام غير المشروع.\n\nشفافية تامة\n\n    لن نقوم بمشاركة بياناتك الشخصية مع أي طرف ثالث دون موافقتك المسبقة.\n    يُمكنك إدارة بياناتك وتحديثها أو طلب حذفها في أي وقت من خلال إعدادات الحساب أو التواصل معنا.\n\nهدفنا\nضمان تجربة آمنة وموثوقة تلبي احتياجاتك الطبية مع احترام خصوصيتك في كل خطوة.\n\nلمزيد من التفاصيل، يمكنك الاطلاع على النص الكامل لسياسة الخصوصية عبر التطبيق.', NULL, 'privacy', 1, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(4, 'terms Employees', 'شروط واحكام تطبيق الموظفيين', 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.', 'شروط الأستخدام\n=====\n\n توفير معلومات دقيقة\n\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\n\n الالتزام بالمواعيد\n\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\n\nدفع الرسوم\n\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\n\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\n\n الخصوصية وحماية البيانات\n\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'terms', 28, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(5, 'terms Employees', 'شروط واحكام تطبيق الموظفيين', 'Terms of Use\n=====\n\nProviding accurate information\n\nThe user must enter accurate and correct details about his health condition and the purpose of the visit.\n\nThe user is responsible for any incorrect information that may affect the medical service provided.\n\nCommitment to appointments\n\nThe user is required to respect the booked appointments or cancel them in sufficient time if circumstances prevent him from attending.\n\nPayment of fees\n\nThe user must pay any fees associated with the service, whether booking fees or medical consultation fees, through the payment methods available in the application.\n\nThe application is committed to clarifying the payment and refund policy in a transparent manner.\n\nPrivacy and data protection\n\nThe user must agree to the privacy policy that specifies how personal data is collected and used.\nThe applications are committed to protecting user data in accordance with the data protection systems and regulations in the Kingdom.', 'شروط الأستخدام\n=====\n\n توفير معلومات دقيقة\n\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\n\n الالتزام بالمواعيد\n\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\n\nدفع الرسوم\n\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\n\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\n\n الخصوصية وحماية البيانات\n\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'about', 28, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(6, 'terms Employees ', 'شروط واحكام تطبيق الموظفيين', 'Terms of Use\n=====\n\nProviding accurate information\n\nThe user must enter accurate and correct details about his health condition and the purpose of the visit.\n\nThe user is responsible for any incorrect information that may affect the medical service provided.\n\nCommitment to appointments\n\nThe user is required to respect the booked appointments or cancel them in sufficient time if circumstances prevent him from attending.\n\nPayment of fees\n\nThe user must pay any fees associated with the service, whether booking fees or medical consultation fees, through the payment methods available in the application.\n\nThe application is committed to clarifying the payment and refund policy in a transparent manner.\n\nPrivacy and data protection\n\nThe user must agree to the privacy policy that specifies how personal data is collected and used.\nThe applications are committed to protecting user data in accordance with the data protection systems and regulations in the Kingdom.', 'شروط الأستخدام\n=====\n\n توفير معلومات دقيقة\n\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\n\n الالتزام بالمواعيد\n\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\n\nدفع الرسوم\n\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\n\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\n\n الخصوصية وحماية البيانات\n\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'privacy', 28, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(7, 'terms Doctor', 'شروط واحكام تطبيق الاطباء', 'Terms of Use\n=====\n\nProviding accurate information\n\nThe user must enter accurate and correct details about his health condition and the purpose of the visit.\n\nThe user is responsible for any incorrect information that may affect the medical service provided.\n\nCommitment to appointments\n\nThe user is required to respect the booked appointments or cancel them in sufficient time if circumstances prevent him from attending.\n\nPayment of fees\n\nThe user must pay any fees associated with the service, whether booking fees or medical consultation fees, through the payment methods available in the application.\n\nThe application is committed to clarifying the payment and refund policy in a transparent manner.\n\nPrivacy and data protection\n\nThe user must agree to the privacy policy that specifies how personal data is collected and used.\nThe applications are committed to protecting user data in accordance with the data protection systems and regulations in the Kingdom.', 'شروط الأستخدام\n=====\n\n توفير معلومات دقيقة\n\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\n\n الالتزام بالمواعيد\n\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\n\nدفع الرسوم\n\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\n\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\n\n الخصوصية وحماية البيانات\n\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'terms', 3, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(8, 'About Us Doctors', 'عن تطبيق الطبيب', 'About Takaful\n=====\nAn application that makes it easy for users to book medical appointments easily and quickly. The application allows you to browse doctors by specialties, book appointments by date and time, and view exclusive offers and available services. The application is compatible with insurance companies, allowing you to easily choose clinics and covered services.\n\nBook appointments easily: Choose the date and time that suits you with immediate confirmation.\n\nSpecial offers: Discover the latest offers and discounts at clinic complexes.\n\nSecure electronic payment: Various payment options to facilitate the experience.\n\nApplication goal: Provide a comfortable and smooth experience for users to access the best', 'عن تكافل \n=====\nتطبيق يسهّل على المستخدمين حجز المواعيد الطبية بكل سهولة وسرعة. يتيح لك التطبيق استعراض الأطباء حسب التخصصات، حجز المواعيد بالتاريخ والساعة، والاطلاع على العروض الحصرية والخدمات المتوفرة. يتميز التطبيق بتوافقه مع شركات التأمين، مما يتيح لك اختيار العيادات والخدمات المغطاة بسهولة.\n\n    حجز المواعيد بسهولة: اختر التاريخ والساعة المناسبة لك مع تأكيد فوري.\n    عروض خاصة: اكتشف أحدث العروض والتخفيضات في مجمعات العيادات.\n    دفع إلكتروني آمن: خيارات دفع متنوعة لتسهيل التجربة.\n\nهدف التطبيق: تقديم تجربة مريحة وسلسة للمستخدمين للوصول إلى أفضل ', NULL, 'about', 3, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(9, 'Privacy Policy Doctor App', 'سياسة الخصوصية الخاصة بتطبيق الطبيب', 'Privacy Policy\n======\n\nWe are committed to protecting your privacy and ensuring the security of your personal data. Our Privacy Policy is designed to explain how we collect, use, and protect information to the highest standards of security.\n\nWhat do we do with your data?\n\nData Collection: We collect only basic information, such as name, contact information, and booking details, in order to provide the service efficiently.\n\nUse: Your data is used to organize appointments, provide appropriate offers, and ensure that services are compatible with your insurance coverage.\n\nData Protection: We apply modern technologies to protect your data from unauthorized access or illegal use.\n\nComplete Transparency\n\nWe will not share your personal data with any third party without your prior consent.\n\nYou can manage, update, or request deletion of your data at any time through your account settings or by contacting us.\n\nOur Goal\nTo ensure a safe and reliable experience that meets your medical needs while respecting your privacy at every step.\n\nFor more details, you can view the full text of the Privacy Policy via the application.', 'سياسة الخصوصية\n======\n\n\nنحن  ملتزمون بحماية خصوصيتك وضمان أمان بياناتك الشخصية. تم تصميم سياسة الخصوصية لدينا لتوضيح كيفية جمع المعلومات، استخدامها، وحمايتها ضمن أعلى معايير الأمان.\n\nما الذي نفعله ببياناتك؟\n\n    جمع البيانات: نقوم بجمع المعلومات الأساسية فقط، مثل الاسم، بيانات التواصل، وتفاصيل الحجز، بهدف تقديم الخدمة بكفاءة.\n    الاستخدام: تُستخدم بياناتك لتنظيم المواعيد، توفير العروض المناسبة، والتأكد من توافق الخدمات مع تغطية التأمين الخاصة بك.\n    حماية البيانات: نطبق تقنيات حديثة لحماية بياناتك من الوصول غير المصرح به أو الاستخدام غير المشروع.\n\nشفافية تامة\n\n    لن نقوم بمشاركة بياناتك الشخصية مع أي طرف ثالث دون موافقتك المسبقة.\n    يُمكنك إدارة بياناتك وتحديثها أو طلب حذفها في أي وقت من خلال إعدادات الحساب أو التواصل معنا.\n\nهدفنا\nضمان تجربة آمنة وموثوقة تلبي احتياجاتك الطبية مع احترام خصوصيتك في كل خطوة.\n\nلمزيد من التفاصيل، يمكنك الاطلاع على النص الكامل لسياسة الخصوصية عبر التطبيق.', NULL, 'privacy', 3, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
(10, 'terms Pharmacy', 'شروط واحكام تطبيق الصيدلية', 'Terms of Use\n=====\n\nProviding accurate information\n\nThe user must enter accurate and correct details about his health condition and the purpose of the visit.\n\nThe user is responsible for any incorrect information that may affect the medical service provided.\n\nCommitment to appointments\n\nThe user is required to respect the booked appointments or cancel them in sufficient time if circumstances prevent him from attending.\n\nPayment of fees\n\nThe user must pay any fees associated with the service, whether booking fees or medical consultation fees, through the payment methods available in the application.\n\nThe application is committed to clarifying the payment and refund policy in a transparent manner.\n\nPrivacy and data protection\n\nThe user must agree to the privacy policy that specifies how personal data is collected and used.\nThe applications are committed to protecting user data in accordance with the data protection systems and regulations in the Kingdom.', 'شروط الأستخدام\n=====\n\n توفير معلومات دقيقة\n\n    يجب على المستخدم إدخال تفاصيل دقيقة وصحيحة عن حالته الصحية والغرض من الزيارة.\n    يتحمل المستخدم مسؤولية أي معلومات غير صحيحة قد تؤثر على الخدمة الطبية المقدمة.\n\n الالتزام بالمواعيد\n\n    يشترط على المستخدم احترام المواعيد المحجوزة أو إلغاؤها قبل وقت كافٍ إذا طرأت ظروف تمنعه من الحضور.\n\nدفع الرسوم\n\n    يجب على المستخدم دفع أي رسوم مرتبطة بالخدمة، سواء رسوم الحجز أو الاستشارة الطبية، من خلال وسائل الدفع المتاحة في التطبيق.\n\n    يلتزم التطبيق بتوضيح سياسة الدفع والاسترداد بشكل شفاف.\n\n الخصوصية وحماية البيانات\n\n    يجب أن يوافق المستخدم على سياسة الخصوصية التي تحدد كيفية جمع البيانات الشخصية واستخدامها.\n    تلتزم التطبيقات بحماية بيانات المستخدمين وفقًا لأنظمة ولوائح حماية البيانات في المملكة.', NULL, 'terms', 5, 1, '2022-07-14 15:41:15', '2022-07-14 15:41:15'),
